namespace RecipeCommunity.Models;

public class Recipe
{
    public int Id { get; set; }
    public string Title { get; set; } = string.Empty;
    public string Category { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public List<string> Ingredients { get; set; } = [];
    public List<string> Steps { get; set; } = [];
    public int TotalRatings { get; set; }
    public int RatingSum { get; set; }

    public double AverageRating => TotalRatings > 0 ? (double)RatingSum / TotalRatings : 0;
}

public class RecipeSubmission
{
    public string Title { get; set; } = string.Empty;
    public string Category { get; set; } = string.Empty;
    public string Ingredients { get; set; } = string.Empty;
    public string Steps { get; set; } = string.Empty;
}

using RecipeCommunity.Models;

namespace RecipeCommunity.Services;

public class RecipeService
{
    private readonly List<Recipe> _recipes =
    [
        new()
        {
            Id = 1, Title = "Classic Margherita Pizza", Category = "Italian",
            Description = "A simple yet delicious pizza with fresh mozzarella and basil.",
            Ingredients = ["Pizza dough", "San Marzano tomatoes", "Fresh mozzarella", "Fresh basil", "Olive oil", "Salt"],
            Steps = [
                "Preheat oven to 475°F (245°C) with a pizza stone.",
                "Roll out the dough on a floured surface.",
                "Spread crushed tomatoes evenly over the dough.",
                "Tear mozzarella and distribute over the sauce.",
                "Bake for 10–12 minutes until crust is golden.",
                "Top with fresh basil and a drizzle of olive oil."
            ],
            TotalRatings = 12, RatingSum = 53
        },
        new()
        {
            Id = 2, Title = "Spaghetti Carbonara", Category = "Italian",
            Description = "Creamy Roman pasta made with eggs, cheese, and pancetta.",
            Ingredients = ["Spaghetti", "Pancetta", "Eggs", "Pecorino Romano", "Black pepper"],
            Steps = [
                "Cook spaghetti in salted water until al dente.",
                "Crisp the pancetta in a skillet over medium heat.",
                "Whisk eggs with grated Pecorino and pepper.",
                "Toss hot pasta with pancetta, then remove from heat.",
                "Quickly stir in the egg mixture to create a creamy sauce.",
                "Serve immediately with extra cheese and pepper."
            ],
            TotalRatings = 8, RatingSum = 38
        },
        new()
        {
            Id = 3, Title = "Chicken Tikka Masala", Category = "Indian",
            Description = "Tender chicken in a rich, spiced tomato-cream sauce.",
            Ingredients = ["Chicken thighs", "Yogurt", "Garam masala", "Tomato sauce", "Heavy cream", "Onion", "Garlic", "Ginger"],
            Steps = [
                "Marinate chicken in yogurt and spices for at least 1 hour.",
                "Grill or broil chicken until lightly charred.",
                "Sauté onion, garlic, and ginger in a large pan.",
                "Add tomato sauce and garam masala; simmer 15 minutes.",
                "Stir in cream and add the cooked chicken.",
                "Simmer 10 minutes and serve over basmati rice."
            ],
            TotalRatings = 15, RatingSum = 70
        },
        new()
        {
            Id = 4, Title = "Vegetable Pad Thai", Category = "Asian",
            Description = "A vibrant stir-fried noodle dish with a tangy tamarind sauce.",
            Ingredients = ["Rice noodles", "Tofu", "Bean sprouts", "Peanuts", "Tamarind paste", "Fish sauce", "Lime", "Green onions"],
            Steps = [
                "Soak rice noodles in warm water for 20 minutes.",
                "Press and cube tofu, then pan-fry until golden.",
                "Mix tamarind paste, fish sauce, and sugar for the sauce.",
                "Stir-fry noodles with sauce in a hot wok.",
                "Add tofu, bean sprouts, and green onions.",
                "Serve topped with crushed peanuts and lime wedges."
            ],
            TotalRatings = 6, RatingSum = 26
        },
        new()
        {
            Id = 5, Title = "Beef Tacos", Category = "Mexican",
            Description = "Seasoned ground beef in crispy shells with fresh toppings.",
            Ingredients = ["Ground beef", "Taco seasoning", "Taco shells", "Lettuce", "Tomato", "Cheddar cheese", "Sour cream", "Salsa"],
            Steps = [
                "Brown the ground beef in a skillet over medium-high heat.",
                "Add taco seasoning and water; simmer until thickened.",
                "Warm taco shells in the oven.",
                "Fill shells with seasoned beef.",
                "Top with shredded lettuce, diced tomato, and cheese.",
                "Add sour cream and salsa to taste."
            ],
            TotalRatings = 10, RatingSum = 42
        },
        new()
        {
            Id = 6, Title = "Chocolate Lava Cake", Category = "Desserts",
            Description = "Individual cakes with a warm, molten chocolate center.",
            Ingredients = ["Dark chocolate", "Butter", "Eggs", "Sugar", "Flour", "Vanilla extract"],
            Steps = [
                "Preheat oven to 425°F (220°C). Grease ramekins.",
                "Melt chocolate and butter together.",
                "Whisk eggs, sugar, and vanilla; fold into chocolate mixture.",
                "Add flour and gently combine.",
                "Pour into ramekins and bake 12–14 minutes.",
                "Invert onto plates and serve immediately."
            ],
            TotalRatings = 20, RatingSum = 95
        },
        new()
        {
            Id = 7, Title = "Japanese Miso Soup", Category = "Asian",
            Description = "A comforting soup with tofu, seaweed, and umami-rich miso.",
            Ingredients = ["Dashi stock", "White miso paste", "Silken tofu", "Wakame seaweed", "Green onions"],
            Steps = [
                "Bring dashi stock to a gentle simmer.",
                "Rehydrate wakame in water for 5 minutes.",
                "Cube the silken tofu.",
                "Dissolve miso paste in a ladle of warm dashi, then stir into the pot.",
                "Add tofu and wakame; heat through without boiling.",
                "Garnish with sliced green onions."
            ],
            TotalRatings = 5, RatingSum = 22
        },
        new()
        {
            Id = 8, Title = "Guacamole", Category = "Mexican",
            Description = "Fresh, chunky avocado dip with lime and cilantro.",
            Ingredients = ["Avocados", "Lime juice", "Cilantro", "Red onion", "Jalapeño", "Tomato", "Salt"],
            Steps = [
                "Halve and pit the avocados; scoop into a bowl.",
                "Mash to desired consistency with a fork.",
                "Stir in diced onion, jalapeño, and tomato.",
                "Add lime juice, chopped cilantro, and salt.",
                "Mix gently and taste for seasoning.",
                "Serve immediately with tortilla chips."
            ],
            TotalRatings = 9, RatingSum = 40
        },
    ];

    public IReadOnlyList<string> GetCategories() =>
        _recipes.Select(r => r.Category).Distinct().Order().ToList();

    public IReadOnlyList<Recipe> GetByCategory(string category) =>
        _recipes.Where(r => r.Category.Equals(category, StringComparison.OrdinalIgnoreCase)).ToList();

    public Recipe? GetById(int id) =>
        _recipes.FirstOrDefault(r => r.Id == id);

    public void AddRating(int recipeId, int stars)
    {
        var recipe = GetById(recipeId);
        if (recipe is not null && stars is >= 1 and <= 5)
        {
            recipe.TotalRatings++;
            recipe.RatingSum += stars;
        }
    }

    public void AddRecipe(RecipeSubmission submission)
    {
        var newId = _recipes.Max(r => r.Id) + 1;
        _recipes.Add(new Recipe
        {
            Id = newId,
            Title = submission.Title,
            Category = submission.Category,
            Description = $"A community-submitted {submission.Category.ToLowerInvariant()} recipe.",
            Ingredients = submission.Ingredients.Split('\n', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries).ToList(),
            Steps = submission.Steps.Split('\n', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries).ToList(),
        });
    }
}

