﻿@page "/"
@using RecipeCommunity.Services
@inject RecipeService RecipeService

<PageTitle>Recipe Community</PageTitle>

<div class="text-center mb-4">
    <h1>🍳 Recipe Community</h1>
    <p class="lead">Discover and share delicious recipes from around the world.</p>
</div>

<div class="row">
    @foreach (var category in RecipeService.GetCategories())
    {
        <div class="col-md-6 col-lg-3 mb-4">
            <a href="category/@category" class="text-decoration-none">
                <div class="card h-100 shadow-sm category-card">
                    <div class="card-body text-center">
                        <div class="display-4 mb-2">@GetCategoryEmoji(category)</div>
                        <h5 class="card-title">@category</h5>
                        <p class="text-muted">@RecipeService.GetByCategory(category).Count recipes</p>
                    </div>
                </div>
            </a>
        </div>
    }
</div>

@code {
    private static string GetCategoryEmoji(string category) => category switch
    {
        "Italian" => "🍝",
        "Indian" => "🍛",
        "Asian" => "🥢",
        "Mexican" => "🌮",
        "Desserts" => "🍰",
        _ => "🍽️"
    };
}

