@page "/category/{CategoryName}"
@using RecipeCommunity.Services
@inject RecipeService RecipeService

<PageTitle>@CategoryName Recipes</PageTitle>

<h1>@CategoryName Recipes</h1>
<nav aria-label="breadcrumb">
    <ol class="breadcrumb">
        <li class="breadcrumb-item"><a href="/">Home</a></li>
        <li class="breadcrumb-item active">@CategoryName</li>
    </ol>
</nav>

@if (recipes.Count == 0)
{
    <div class="alert alert-info">No recipes found in this category.</div>
}
else
{
    <div class="row">
        @foreach (var recipe in recipes)
        {
            <div class="col-md-6 mb-4">
                <div class="card h-100 shadow-sm">
                    <div class="card-body">
                        <h5 class="card-title">@recipe.Title</h5>
                        <p class="card-text">@recipe.Description</p>
                        <div class="mb-2">
                            <span class="text-warning">
                                @for (int i = 1; i <= 5; i++)
                                {
                                    @(i <= (int)Math.Round(recipe.AverageRating) ? "★" : "☆")
                                }
                            </span>
                            <small class="text-muted">(@recipe.TotalRatings ratings)</small>
                        </div>
                        <a href="recipe/@recipe.Id" class="btn btn-outline-primary btn-sm">View Recipe</a>
                    </div>
                </div>
            </div>
        }
    </div>
}

@code {
    [Parameter] public string CategoryName { get; set; } = string.Empty;

    private IReadOnlyList<RecipeCommunity.Models.Recipe> recipes = [];

    protected override void OnParametersSet()
    {
        recipes = RecipeService.GetByCategory(CategoryName);
    }
}

@page "/recipe/{Id:int}"
@using RecipeCommunity.Services
@inject RecipeService RecipeService

<PageTitle>@(recipe?.Title ?? "Recipe")</PageTitle>

@if (recipe is null)
{
    <div class="alert alert-warning">Recipe not found.</div>
}
else
{
    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="/">Home</a></li>
            <li class="breadcrumb-item"><a href="category/@recipe.Category">@recipe.Category</a></li>
            <li class="breadcrumb-item active">@recipe.Title</li>
        </ol>
    </nav>

    <h1>@recipe.Title</h1>
    <p class="lead">@recipe.Description</p>

    <StarRating RecipeId="recipe.Id" CurrentAverage="recipe.AverageRating" TotalRatings="recipe.TotalRatings" />

    <div class="row mt-4">
        <div class="col-md-4">
            <div class="card shadow-sm mb-4">
                <div class="card-header"><h5 class="mb-0">🧾 Ingredients</h5></div>
                <ul class="list-group list-group-flush">
                    @foreach (var ingredient in recipe.Ingredients)
                    {
                        <li class="list-group-item">@ingredient</li>
                    }
                </ul>
            </div>
        </div>
        <div class="col-md-8">
            <div class="card shadow-sm">
                <div class="card-header"><h5 class="mb-0">📝 Instructions</h5></div>
                <div class="card-body">
                    <ol class="mb-0">
                        @foreach (var step in recipe.Steps)
                        {
                            <li class="mb-2">@step</li>
                        }
                    </ol>
                </div>
            </div>
        </div>
    </div>
}

@code {
    [Parameter] public int Id { get; set; }

    private RecipeCommunity.Models.Recipe? recipe;

    protected override void OnParametersSet()
    {
        recipe = RecipeService.GetById(Id);
    }
}

@rendermode InteractiveServer
@using RecipeCommunity.Services
@inject RecipeService RecipeService

<div class="my-3">
    <span class="me-2 fs-5">
        @for (int i = 1; i <= 5; i++)
        {
            var star = i;
            <span role="button" class="@(star <= hoverStar ? "text-warning" : "text-secondary")"
                  style="cursor:pointer;"
                  @onmouseover="() => hoverStar = star"
                  @onmouseout="() => hoverStar = 0"
                  @onclick="() => Rate(star)">
                ★
            </span>
        }
    </span>
    <span class="text-muted">
        @if (userRating > 0)
        {
            <text>You rated this @userRating/5 · </text>
        }
        @CurrentAverage.ToString("0.0") avg (@TotalRatings ratings)
    </span>
</div>

@code {
    [Parameter] public int RecipeId { get; set; }
    [Parameter] public double CurrentAverage { get; set; }
    [Parameter] public int TotalRatings { get; set; }

    private int hoverStar;
    private int userRating;

    private void Rate(int stars)
    {
        if (userRating > 0) return; // one rating per session
        userRating = stars;
        RecipeService.AddRating(RecipeId, stars);
        var recipe = RecipeService.GetById(RecipeId);
        if (recipe is not null)
        {
            CurrentAverage = recipe.AverageRating;
            TotalRatings = recipe.TotalRatings;
        }
    }
}

@page "/submit"
@rendermode InteractiveServer
@using RecipeCommunity.Models
@using RecipeCommunity.Services
@inject RecipeService RecipeService

<PageTitle>Submit a Recipe</PageTitle>

<h1>📤 Submit a Recipe</h1>
<p>Share your favorite recipe with the community!</p>

@if (submitted)
{
    <div class="alert alert-success">
        <strong>Thank you!</strong> Your recipe "<strong>@submission.Title</strong>" has been submitted.
        <a href="/">Browse recipes</a>
    </div>
}
else
{
    <div class="row">
        <div class="col-md-8">
            <EditForm Model="submission" OnValidSubmit="HandleSubmit" FormName="recipeForm">
                <DataAnnotationsValidator />
                <ValidationSummary />

                <div class="mb-3">
                    <label for="title" class="form-label">Recipe Title</label>
                    <InputText id="title" @bind-Value="submission.Title" class="form-control" placeholder="e.g., Grandma's Apple Pie" />
                </div>

                <div class="mb-3">
                    <label for="category" class="form-label">Category</label>
                    <InputSelect id="category" @bind-Value="submission.Category" class="form-select">
                        <option value="">-- Select a category --</option>
                        <option value="Italian">Italian</option>
                        <option value="Indian">Indian</option>
                        <option value="Asian">Asian</option>
                        <option value="Mexican">Mexican</option>
                        <option value="Desserts">Desserts</option>
                        <option value="Other">Other</option>
                    </InputSelect>
                </div>

                <div class="mb-3">
                    <label for="ingredients" class="form-label">Ingredients (one per line)</label>
                    <InputTextArea id="ingredients" @bind-Value="submission.Ingredients" class="form-control" rows="6"
                                   placeholder="2 cups flour&#10;1 cup sugar&#10;3 large apples" />
                </div>

                <div class="mb-3">
                    <label for="steps" class="form-label">Steps (one per line)</label>
                    <InputTextArea id="steps" @bind-Value="submission.Steps" class="form-control" rows="6"
                                   placeholder="Preheat oven to 350°F.&#10;Mix dry ingredients.&#10;Add wet ingredients." />
                </div>

                <button type="submit" class="btn btn-primary"
                        disabled="@(!IsValid)">
                    Submit Recipe
                </button>
            </EditForm>
        </div>
    </div>
}

@code {
    private RecipeSubmission submission = new();
    private bool submitted;

    private bool IsValid =>
        !string.IsNullOrWhiteSpace(submission.Title) &&
        !string.IsNullOrWhiteSpace(submission.Category) &&
        !string.IsNullOrWhiteSpace(submission.Ingredients) &&
        !string.IsNullOrWhiteSpace(submission.Steps);

    private void HandleSubmit()
    {
        if (!IsValid) return;
        RecipeService.AddRecipe(submission);
        submitted = true;
    }
}

