+@rendermode InteractiveServer
+@using RecipeCommunity.Services
+@inject RecipeService RecipeService
+
+<div class="my-3">
+    <span class="me-2 fs-5">
+        @for (int i = 1; i <= 5; i++)
+        {
+            var star = i;
+            <span role="button" class="@(star <= hoverStar ? "text-warning" : "text-secondary")"
+                  style="cursor:pointer;"
+                  @onmouseover="() => hoverStar = star"
+                  @onmouseout="() => hoverStar = 0"
+                  @onclick="() => Rate(star)">
+                ★
+            </span>
+        }
+    </span>
+    <span class="text-muted">
+        @if (userRating > 0)
+        {
+            <text>You rated this @userRating/5 · </text>
+        }
+        @CurrentAverage.ToString("0.0") avg (@TotalRatings ratings)
+    </span>
+</div>
+
+@code {
+    [Parameter] public int RecipeId { get; set; }
+    [Parameter] public double CurrentAverage { get; set; }
+    [Parameter] public int TotalRatings { get; set; }
+
+    private int hoverStar;
+    private int userRating;
+
+    private void Rate(int stars)
+    {
+        if (userRating > 0) return; // one rating per session
+        userRating = stars;
+        RecipeService.AddRating(RecipeId, stars);
+        var recipe = RecipeService.GetById(RecipeId);
+        if (recipe is not null)
+        {
+            CurrentAverage = recipe.AverageRating;
+            TotalRatings = recipe.TotalRatings;
+        }
+    }
+}
